int findSecondsToTransform(String s) {
    int cnt0 = 0, cnt1 = 0;
    for (char c : s.toCharArray()) {
        if (c == '0') cnt0++;
        else cnt1++;
    }
    return Math.min(cnt0, cnt1);
}
```

